const express = require('express');
const axios = require('axios');
const morgan = require('morgan');

const app = express();
const PORT = process.env.PORT || 3000;

app.use(morgan(':method :url :status :res[content-length] - :response-time ms'));

const VALID_API_KEYS = new Set(['your-secure-api-key-1', 'your-secure-api-key-2']); // Replace with your valid keys

app.use((req, res, next) => {
    const apiKey = req.query.api_key;
    if (apiKey && VALID_API_KEYS.has(apiKey)) {
        req.headers['x-api-key'] = apiKey; // Forwarding API key in headers
    } else {
        return res.status(403).send('Forbidden: Invalid API Key');
    }
    next();
});

app.use('/api/:service/*', async (req, res) => {
    const service = req.params.service;
    const url = `http://backend-service/${service}${req.path.replace(`/api/${service}`, '')}`;
    
    try {
        const response = await axios({
            method: req.method,
            url: url,
            headers: req.headers,
            data: req.body,
        });
        res.status(response.status).send(response.data);
    } catch (error) {
        res.status(error.response ? error.response.status : 500).send(error.message);
    }
});

